using System;
using System.Linq;
using System.Reflection;

var asm = Assembly.LoadFrom(
    System.IO.Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
        ".nuget/packages/microsoft.entityframeworkcore.cosmos/9.0.0/lib/net8.0/Microsoft.EntityFrameworkCore.Cosmos.dll"));

// Find extension methods related to entity type builder
foreach (var t in asm.GetExportedTypes()
    .Where(t => t.Name.Contains("CosmosEntityType") || t.Name.Contains("CosmosModel")))
{
    Console.WriteLine($"=== {t.FullName} ===");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.Instance)
        .Where(m => !m.IsSpecialName))
    {
        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({parms})");
    }
}

// Also search for anything with "Discriminator" or "JsonId" or "Id" in method names
Console.WriteLine("\n=== Methods containing 'Id' or 'Discriminator' or 'Sync' ===");
foreach (var t in asm.GetExportedTypes())
{
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.Instance)
        .Where(m => !m.IsSpecialName && 
            (m.Name.Contains("Id") || m.Name.Contains("Discriminator") || m.Name.Contains("Sync"))))
    {
        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {t.Name}.{m.Name}({parms})");
    }
}
EOF

