using System;
using System.Linq;
using System.Reflection;

var asm = Assembly.LoadFrom(
    System.IO.Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
        ".nuget/packages/microsoft.entityframeworkcore.cosmos/9.0.0/lib/net8.0/Microsoft.EntityFrameworkCore.Cosmos.dll"));

// Check JsonIdDefinition for separator
var jidType = asm.GetTypes().FirstOrDefault(t => t.Name == "JsonIdDefinition");
if (jidType != null)
{
    Console.WriteLine($"=== {jidType.FullName} ===");
    foreach (var f in jidType.GetFields(BindingFlags.Public | BindingFlags.Static | BindingFlags.NonPublic))
        Console.WriteLine($"  Field: {f.Name} = {f.GetValue(null)}");
    foreach (var p in jidType.GetProperties(BindingFlags.Public | BindingFlags.Static | BindingFlags.Instance | BindingFlags.NonPublic))
        Console.WriteLine($"  Prop: {p.Name} ({p.PropertyType.Name})");
    foreach (var m in jidType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.NonPublic | BindingFlags.Static)
        .Where(m => !m.IsSpecialName))
    {
        Console.WriteLine($"  Method: {m.Name}");
    }
    foreach (var c in jidType.GetConstructors(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance))
    {
        var parms = string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  Ctor: ({parms})");
    }
}

// Also check CosmosEventId for sync warnings
var eventIdType = asm.GetTypes().FirstOrDefault(t => t.Name == "CosmosEventId");
if (eventIdType != null)
{
    Console.WriteLine($"\n=== {eventIdType.FullName} ===");
    foreach (var f in eventIdType.GetFields(BindingFlags.Public | BindingFlags.Static))
        Console.WriteLine($"  {f.Name}");
}
EOF
