        // documents (and raw SQL like WHERE c.Discriminator = 'Blog') keep working.
        modelBuilder.Model.SetEmbeddedDiscriminatorName("Discriminator");

        // Breaking change 2: EF9 Cosmos no longer includes the discriminator in the
        // synthesized JSON "id". Existing documents use "Blog|1" format.
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // Breaking change 3: HasIndex now throws for the Cosmos provider because
        // Cosmos DB does not support secondary indexes through EF Core.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
